#include <stdio.h>
#include <math.h>
#define MOD 1000000007
long long power(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}
long long modInverse(long long a) {
    return power(a, MOD - 2);
}
long long nCr(long long n, long long r) {
    long long res = 1;
    for (long long i = 1; i <= r; i++) {
        res = (res * (n - i + 1)) % MOD;
        res = (res * modInverse(i)) % MOD;
    }
    return res;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long n, k;
        scanf("%lld %lld", &n, &k);
        long long ans = 0;
        for (long long i = k; i <= n; i++) {
            long long cnt = nCr(i - 1, k - 1);
            ans = (ans + cnt) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

