def power(a, b):
    res = 1
    while b > 0:
        if b % 2 == 1: res = (res * a) % MOD
        a = (a * a) % MOD
        b >>= 1
    return res

def modInverse(a):
    return power(a, MOD - 2)

def nCr(n, r):
    res = 1
    for i in range(1, r + 1):
        res = (res * (n - i + 1)) % MOD
        res = (res * modInverse(i)) % MOD
    return res

